import{_ as i,o as a,c as r,ag as l}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"COURS : L’ACCIDENT VASCULAIRE CÉRÉBRAL (AVC)","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/AVC-neuro.md","filePath":"matieres/sante/cours/AVC-neuro.md"}'),t={name:"matieres/sante/cours/AVC-neuro.md"};function n(s,e,o,u,c,d){return a(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="cours-l-accident-vasculaire-cerebral-avc" tabindex="-1">COURS : L’ACCIDENT VASCULAIRE CÉRÉBRAL (AVC) <a class="header-anchor" href="#cours-l-accident-vasculaire-cerebral-avc" aria-label="Permalink to &quot;COURS : L’ACCIDENT VASCULAIRE CÉRÉBRAL (AVC)&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>L’accident vasculaire cérébral (AVC) est une <strong>interruption brutale de la circulation sanguine dans une partie du cerveau</strong>, entraînant une <strong>privation d’oxygène des cellules cérébrales</strong>.</p><p>👉 Cette situation provoque la <strong>mort des cellules nerveuses</strong> si la circulation n’est pas rapidement rétablie.</p><p>📌 L’AVC est une <strong>urgence médicale</strong>.</p><hr><h2 id="_2️⃣-types-d-avc" tabindex="-1">2️⃣ Types d’AVC <a class="header-anchor" href="#_2️⃣-types-d-avc" aria-label="Permalink to &quot;2️⃣ Types d’AVC&quot;">​</a></h2><h3 id="🔹-avc-ischemique" tabindex="-1">🔹 AVC ischémique <a class="header-anchor" href="#🔹-avc-ischemique" aria-label="Permalink to &quot;🔹 AVC ischémique&quot;">​</a></h3><p>C’est le type <strong>le plus fréquent (environ 80 % des cas)</strong>.</p><p>Il est causé par <strong>l’obstruction d’une artère cérébrale par un caillot sanguin</strong>.</p><p>Causes possibles :</p><ul><li>Thrombose cérébrale</li><li>Embolie (caillot provenant du cœur ou d’une autre artère)</li><li>Athérosclérose</li></ul><hr><h3 id="🔹-avc-hemorragique" tabindex="-1">🔹 AVC hémorragique <a class="header-anchor" href="#🔹-avc-hemorragique" aria-label="Permalink to &quot;🔹 AVC hémorragique&quot;">​</a></h3><p>Il est causé par <strong>la rupture d’un vaisseau sanguin dans le cerveau</strong>.</p><p>Le sang s’accumule dans le tissu cérébral et <strong>comprimes les structures du cerveau</strong>.</p><p>Facteurs fréquents :</p><ul><li>Hypertension artérielle</li><li>Malformation vasculaire</li><li>Traumatisme</li></ul><hr><h3 id="🔹-accident-ischemique-transitoire-ait" tabindex="-1">🔹 Accident ischémique transitoire (AIT) <a class="header-anchor" href="#🔹-accident-ischemique-transitoire-ait" aria-label="Permalink to &quot;🔹 Accident ischémique transitoire (AIT)&quot;">​</a></h3><ul><li>Interruption <strong>temporaire</strong> de la circulation cérébrale</li><li>Les symptômes disparaissent généralement <strong>en moins de 24 heures</strong></li></ul><p>⚠️ L’AIT est un <strong>signe d’alerte d’un AVC futur</strong>.</p><hr><h2 id="_3️⃣-facteurs-de-risque" tabindex="-1">3️⃣ Facteurs de risque <a class="header-anchor" href="#_3️⃣-facteurs-de-risque" aria-label="Permalink to &quot;3️⃣ Facteurs de risque&quot;">​</a></h2><p>Les principaux facteurs de risque sont :</p><ul><li>Hypertension artérielle</li><li>Diabète</li><li>Hypercholestérolémie</li><li>Tabagisme</li><li>Obésité</li><li>Sédentarité</li><li>Consommation excessive d’alcool</li><li>Maladies cardiaques</li><li>Âge avancé</li><li>Antécédents familiaux</li></ul><hr><h2 id="_4️⃣-signes-et-symptomes" tabindex="-1">4️⃣ Signes et symptômes <a class="header-anchor" href="#_4️⃣-signes-et-symptomes" aria-label="Permalink to &quot;4️⃣ Signes et symptômes&quot;">​</a></h2><p>Les symptômes apparaissent <strong>brutalement</strong>.</p><p>Signes fréquents :</p><ul><li>Faiblesse ou paralysie d’un côté du corps (hémiplégie)</li><li>Engourdissement du visage, du bras ou de la jambe</li><li>Difficulté à parler (aphasie)</li><li>Difficulté à comprendre</li><li>Troubles de la vision</li><li>Vertiges</li><li>Perte d’équilibre</li><li>Maux de tête intenses (surtout dans l’AVC hémorragique)</li></ul><p>📌 Test FAST (reconnaissance rapide) :</p><ul><li><strong>F</strong> : Face (visage asymétrique)</li><li><strong>A</strong> : Arm (faiblesse d’un bras)</li><li><strong>S</strong> : Speech (trouble de la parole)</li><li><strong>T</strong> : Time (appeler immédiatement les urgences)</li></ul><hr><h2 id="_5️⃣-diagnostic" tabindex="-1">5️⃣ Diagnostic <a class="header-anchor" href="#_5️⃣-diagnostic" aria-label="Permalink to &quot;5️⃣ Diagnostic&quot;">​</a></h2><p>Le diagnostic repose sur plusieurs examens :</p><h3 id="🩺-examen-clinique" tabindex="-1">🩺 Examen clinique <a class="header-anchor" href="#🩺-examen-clinique" aria-label="Permalink to &quot;🩺 Examen clinique&quot;">​</a></h3><ul><li>Évaluation neurologique</li><li>Recherche des signes neurologiques</li></ul><h3 id="📊-examens-complementaires" tabindex="-1">📊 Examens complémentaires <a class="header-anchor" href="#📊-examens-complementaires" aria-label="Permalink to &quot;📊 Examens complémentaires&quot;">​</a></h3><ul><li><strong>Scanner cérébral (TDM)</strong></li><li><strong>IRM cérébrale</strong></li><li><strong>Électrocardiogramme (ECG)</strong></li><li><strong>Analyses sanguines</strong></li><li><strong>Échographie des artères carotides</strong></li></ul><hr><h2 id="_6️⃣-complications" tabindex="-1">6️⃣ Complications <a class="header-anchor" href="#_6️⃣-complications" aria-label="Permalink to &quot;6️⃣ Complications&quot;">​</a></h2><p>L’AVC peut entraîner :</p><ul><li>Paralysie</li><li>Troubles de la parole</li><li>Troubles de la mémoire</li><li>Difficultés de déglutition</li><li>Dépression</li><li>Handicap permanent</li><li>Décès</li></ul><hr><h2 id="_7️⃣-traitement" tabindex="-1">7️⃣ Traitement <a class="header-anchor" href="#_7️⃣-traitement" aria-label="Permalink to &quot;7️⃣ Traitement&quot;">​</a></h2><h3 id="🏥-traitement-d-urgence" tabindex="-1">🏥 Traitement d’urgence <a class="header-anchor" href="#🏥-traitement-d-urgence" aria-label="Permalink to &quot;🏥 Traitement d’urgence&quot;">​</a></h3><p>Dans l’AVC ischémique :</p><ul><li><strong>Thrombolyse</strong> (médicament qui dissout le caillot)</li><li><strong>Thrombectomie</strong> (retrait du caillot)</li></ul><p>Dans l’AVC hémorragique :</p><ul><li>Contrôle de la pression artérielle</li><li>Chirurgie dans certains cas</li></ul><hr><h3 id="💊-traitement-medical" tabindex="-1">💊 Traitement médical <a class="header-anchor" href="#💊-traitement-medical" aria-label="Permalink to &quot;💊 Traitement médical&quot;">​</a></h3><ul><li>Antiagrégants plaquettaires</li><li>Anticoagulants</li><li>Médicaments pour contrôler la tension</li><li>Médicaments pour contrôler le cholestérol</li></ul><hr><h2 id="_8️⃣-reeducation" tabindex="-1">8️⃣ Rééducation <a class="header-anchor" href="#_8️⃣-reeducation" aria-label="Permalink to &quot;8️⃣ Rééducation&quot;">​</a></h2><p>Après un AVC, la rééducation est essentielle :</p><ul><li>Kinésithérapie</li><li>Orthophonie</li><li>Ergothérapie</li><li>Rééducation cognitive</li></ul><p>👉 L’objectif est de <strong>récupérer les fonctions perdues et améliorer l’autonomie</strong>.</p><hr><h2 id="_9️⃣-prevention" tabindex="-1">9️⃣ Prévention <a class="header-anchor" href="#_9️⃣-prevention" aria-label="Permalink to &quot;9️⃣ Prévention&quot;">​</a></h2><p>Mesures de prévention :</p><ul><li>Contrôle de la pression artérielle</li><li>Contrôle du diabète</li><li>Arrêt du tabac</li><li>Alimentation équilibrée</li><li>Activité physique régulière</li><li>Contrôle du cholestérol</li><li>Suivi médical régulier</li></ul><hr><h2 id="🔟-role-infirmier-👨‍⚕️👩‍⚕️" tabindex="-1">🔟 Rôle infirmier 👨‍⚕️👩‍⚕️ <a class="header-anchor" href="#🔟-role-infirmier-👨‍⚕️👩‍⚕️" aria-label="Permalink to &quot;🔟 Rôle infirmier 👨‍⚕️👩‍⚕️&quot;">​</a></h2><p>Le rôle infirmier est essentiel dans la prise en charge du patient victime d’AVC :</p><ul><li>Surveillance des <strong>signes neurologiques</strong></li><li>Surveillance des <strong>signes vitaux</strong></li><li>Prévention des complications (escarres, infections)</li><li>Aide à l’alimentation et à la déglutition</li><li>Administration des traitements</li><li>Participation à la rééducation</li><li>Éducation du patient et de la famille</li><li>Soutien psychologique</li></ul>',67)])])}const p=i(t,[["render",n]]);export{h as __pageData,p as default};
